CODE_EXAMPLE:
// Before
int getTotalOutstandingAndSetReadyForSummaries() {
  int total = 0;
  for (int i = 0; i < invoices.length; i++) {
    Invoice invoice = invoices[i];
    int outstanding = invoice.getOutstanding();
    total += outstanding;
    invoice.setReadyForSummary();
  }
  return total;
}

// After
int getTotalOutstanding() {
  int total = 0;
  for (int i = 0; i < invoices.length; i++) {
    total += invoices[i].getOutstanding();
  }
  return total;
}

void setReadyForSummaries() {
  for (int i = 0; i < invoices.length; i++) {
    invoices[i].setReadyForSummary();
  }
}

